120	    Math.PI / 4 + Math.PI / (openingFocus ? 1.9 : 2.2),
121	  );
122	
123	  const arcPts = curve.getPoints(28).map((p) => new THREE.Vector3(p.x, PLAN_Y + 0.03, -p.y));
124	
125	  const arcGeom = new THREE.BufferGeometry().setFromPoints(arcPts);
126	
127	  const arc = new THREE.Line(
128	    arcGeom,
129	
130	    new THREE.LineBasicMaterial({
131	      color: (() => {
132	        const p = getPlanPalette();
133	        return openingFocus ? p.doorSwingFocus : p.doorSwing;
134	      })(),
135	      linewidth: 1,
136	    }),
137	  );
138	
139	  arc.position.set(px, 0, pz);
140	
141	  arc.rotation.y = Math.atan2(seg.nz, seg.nx);
142	
143	  g.add(arc);
144	
145	  g.userData.bimPickId = door.id;
146	
147	  return g;
148	}
