150	export function planWindowMesh(
151	  win: Extract<Element, { kind: 'window' }>,
152	
153	  wall: Extract<Element, { kind: 'wall' }>,
154	
155	  selectedId?: string,
156	
157	  openingFocus?: boolean,
158	): THREE.Group {
