239	/** Match kernel `stair_riser_count_plan_proxy` (rise / riser when levels resolve). */
240	export function computeStairPlanRiserCount(
241	  stair: Extract<Element, { kind: 'stair' }>,
242	  elementsById?: Record<string, Element>,
243	): number {
244	  const sx = stair.runStartMm.xMm / 1000;
245	  const sz = stair.runStartMm.yMm / 1000;
246	  const ex = stair.runEndMm.xMm / 1000;
247	  const ez = stair.runEndMm.yMm / 1000;
248	  const lenM = Math.max(1e-6, Math.hypot(ex - sx, ez - sz));
249	  const lenMm = lenM * 1000;
250	
251	  if (elementsById) {
252	    const bl = elementsById[stair.baseLevelId];
253	    const tl = elementsById[stair.topLevelId];
254	    if (bl?.kind === 'level' && tl?.kind === 'level') {
255	      const riseMm = Math.abs(tl.elevationMm - bl.elevationMm);
256	      if (riseMm > 1e-3) {
257	        const r = Math.max(stair.riserMm, 1e-6);
258	        const n = Math.round(riseMm / r);
259	        return Math.max(2, Math.min(36, n));
260	      }
261	    }
262	  }
263	
264	  const t = Math.max(stair.treadMm, 1e-6);
265	  const n2 = Math.round(lenMm / t);
266	  return Math.max(2, Math.min(36, n2));
267	}
