271	export function stairPlanThree(
272	  stair: Extract<Element, { kind: 'stair' }>,
273	  elementsById?: Record<string, Element>,
274	  wireDoc?: StairPlanWireDocOverlays | null,
275	): THREE.Group | null {
276	  const sx = stair.runStartMm.xMm / 1000;
277	  const sz = stair.runStartMm.yMm / 1000;
278	  const ex = stair.runEndMm.xMm / 1000;
279	  const ez = stair.runEndMm.yMm / 1000;
280	  const dx = ex - sx;
281	  const dz = ez - sz;
282	  const len = Math.max(1e-6, Math.hypot(dx, dz));
283	  const uxDir = dx / len;
284	  const uzDir = dz / len;
285	  const px = -uzDir * (stair.widthMm / 2000);
286	
287	  const pz = uxDir * (stair.widthMm / 2000);
288	
289	  const g = new THREE.Group();
290	
291	  const outline = [
292	    new THREE.Vector3(sx + px, PLAN_Y + 0.012, sz + pz),
293	
294	    new THREE.Vector3(ex + px, PLAN_Y + 0.012, ez + pz),
295	
296	    new THREE.Vector3(ex - px, PLAN_Y + 0.012, ez - pz),
297	
298	    new THREE.Vector3(sx - px, PLAN_Y + 0.012, sz - pz),
299	
300	    new THREE.Vector3(sx + px, PLAN_Y + 0.012, sz + pz),
301	  ];
302	
303	  g.add(
304	    new THREE.Line(
305	      new THREE.BufferGeometry().setFromPoints(outline),
306	      new THREE.LineBasicMaterial({
307	        color: getPlanPalette().dimAlt,
308	        transparent: true,
309	        opacity: 0.92,
310	      }),
311	    ),
312	  );
313	
314	  const nSteps = computeStairPlanRiserCount(stair, elementsById);
315	  const stepLen = len / nSteps;
316	
317	  const runOffX = uxDir * stepLen;
318	
319	  const runOffZ = uzDir * stepLen;
320	
321	  for (let i = 0; i <= nSteps; i++) {
322	    const t = sx + uxDir * stepLen * i;
323	
324	    const w = sz + uzDir * stepLen * i;
325	
326	    const p1 = new THREE.Vector3(t + px, PLAN_Y + 0.018, w + pz);
327	
328	    const p2 = new THREE.Vector3(t - px, PLAN_Y + 0.018, w - pz);
329	
330	    g.add(
331	      new THREE.Line(
332	        new THREE.BufferGeometry().setFromPoints([p1, p2]),
333	        new THREE.LineBasicMaterial({
334	          color: getPlanPalette().hairline,
335	          transparent: true,
336	          opacity: 0.55,
337	        }),
338	      ),
339	    );
340	
341	    if (i < nSteps) {
342	      const c1 = new THREE.Vector3(
343	        t + runOffX + px * 0.15,
344	        PLAN_Y + 0.018,
345	        w + runOffZ + pz * 0.15,
346	      );
347	
348	      const c2 = new THREE.Vector3(
349	        t + runOffX - px * 0.15,
350	        PLAN_Y + 0.018,
351	        w + runOffZ - pz * 0.15,
352	      );
353	
354	      g.add(
355	        new THREE.Line(
356	          new THREE.BufferGeometry().setFromPoints([c1, c2]),
357	          new THREE.LineBasicMaterial({
358	            color: getPlanPalette().hairlineStrong,
359	            transparent: true,
360	            opacity: 0.45,
361	          }),
362	        ),
363	      );
364	    }
365	  }
366	
367	  if (wireDoc) {
368	    const mx = (sx + ex) * 0.5;
369	    const mz = (sz + ez) * 0.5;
370	    const yDoc = PLAN_Y + 0.024;
371	    let bx = uxDir;
372	    let bz = uzDir;
373	    if (
374	      wireDoc.runBearingDegCcFromPlanX !== undefined &&
375	      Number.isFinite(wireDoc.runBearingDegCcFromPlanX)
376	    ) {
377	      const rad = (wireDoc.runBearingDegCcFromPlanX * Math.PI) / 180;
378	      bx = Math.cos(rad);
379	      bz = Math.sin(rad);
380	    }
381	    const alen = Math.min(len, 0.55) * 0.35;
382	    const tip = new THREE.Vector3(mx + bx * alen * 0.45, yDoc, mz + bz * alen * 0.45);
383	    const tail = new THREE.Vector3(mx - bx * alen * 0.55, yDoc, mz - bz * alen * 0.55);
384	    const arrMat = new THREE.LineBasicMaterial({
385	      color: getPlanPalette().dimLine,
386	      transparent: true,
387	      opacity: 0.88,
388	    });
389	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tail, tip]), arrMat));
390	    const perpX = -bz * 0.06;
391	    const perpZ = bx * 0.06;
392	    const b1 = new THREE.Vector3(tip.x - bx * 0.12 + perpX, yDoc, tip.z - bz * 0.12 + perpZ);
393	    const b2 = new THREE.Vector3(tip.x - bx * 0.12 - perpX, yDoc, tip.z - bz * 0.12 - perpZ);
394	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tip, b1]), arrMat));
395	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([tip, b2]), arrMat));
396	
397	    const ph = wireDoc.stairDocumentationPlaceholders_v0;
398	    if (ph?.bottomLandingFootprintBoundsMm && ph?.topLandingFootprintBoundsMm) {
399	      const yLand = PLAN_Y + 0.021;
400	      const landMat = new THREE.LineBasicMaterial({
401	        color: getPlanPalette().windowFillBackline,
402	        transparent: true,
403	        opacity: 0.52,
404	      });
405	      for (const b of [ph.bottomLandingFootprintBoundsMm, ph.topLandingFootprintBoundsMm]) {
406	        const x0 = b.minXmMm / 1000;
407	        const x1 = b.maxXmMm / 1000;
408	        const z0 = b.minYmMm / 1000;
409	        const z1 = b.maxYmMm / 1000;
410	        const ring = [
411	          new THREE.Vector3(x0, yLand, z0),
412	          new THREE.Vector3(x1, yLand, z0),
413	          new THREE.Vector3(x1, yLand, z1),
414	          new THREE.Vector3(x0, yLand, z1),
415	          new THREE.Vector3(x0, yLand, z0),
416	        ];
417	        g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(ring), landMat));
418	      }
419	    }
420	
421	    const ann =
422	      wireDoc.stairPlanSectionDocumentationLabel?.trim() || wireDoc.planUpDownLabel?.trim();
423	    if (ann) {
424	      const lx = sx + uxDir * Math.min(len * 0.2, 0.35);
425	      const lz = sz + uzDir * Math.min(len * 0.2, 0.35);
426	      const tagScale = wireDoc.stairPlanSectionDocumentationLabel ? 0.62 : 0.85;
427	      g.add(planAnnotationLabelSprite(lx, lz, ann, stair.id, tagScale));
428	    }
429	
430	    if (wireDoc.stairPlanBreakVisibilityToken === 'cutSplitsSpan') {
431	      const zx = mx - bz * (stair.widthMm / 2000) * 0.35;
432	      const zz = mz + bx * (stair.widthMm / 2000) * 0.35;
433	      const zig = 0.04;
434	      const p0 = new THREE.Vector3(zx - bx * zig, PLAN_Y + 0.026, zz - bz * zig);
435	      const p1 = new THREE.Vector3(zx + bx * zig, PLAN_Y + 0.026, zz + bz * zig);
436	      const p2 = new THREE.Vector3(zx + bx * zig * 2, PLAN_Y + 0.026, zz + bz * zig * 2);
437	      const brkMat = new THREE.LineBasicMaterial({
438	        color: getPlanPalette().dimWitness,
439	        transparent: true,
440	        opacity: 0.7,
441	      });
442	      g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([p0, p1]), brkMat));
443	      g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints([p1, p2]), brkMat));
444	    }
445	  }
446	
447	  g.userData.bimPickId = stair.id;
448	
449	  return g;
450	}
