452	export function roomMesh(
453	  room: Extract<Element, { kind: 'room' }>,
454	  presentation?: PlanPresentationPreset,
455	  opts?: { schemeColorHex?: string; roomFillOpacityScale?: number },
456	): THREE.Mesh {
457	  const scheme = presentation ?? 'default';
458	
459	  const shape = new THREE.Shape();
460	
461	  const o = room.outlineMm[0];
462	
463	  if (!o) return new THREE.Mesh();
464	
465	  // Shape lives in XY; rotate mesh −90°X so planar Y aligns with world −Z.
466	
467	  shape.moveTo(ux(o.xMm), -uz(o.yMm));
468	
469	  for (let i = 1; i < room.outlineMm.length; i++) {
470	    const p = room.outlineMm[i];
471	
472	    if (p) shape.lineTo(ux(p.xMm), -uz(p.yMm));
473	  }
474	
475	  shape.closePath();
476	
477	  const geo = new THREE.ShapeGeometry(shape);
478	
479	  const seed =
480	    typeof room.programmeCode === 'string' && room.programmeCode.trim()
481	      ? room.programmeCode.trim()
482	      : room.id;
483	
484	  const fill =
485	    scheme === 'room_scheme'
486	      ? {
487	          opacity: 0.34,
488	
489	          color:
490	            opts?.schemeColorHex && /^#[0-9a-fA-F]{6}$/.test(opts.schemeColorHex)
491	              ? opts.schemeColorHex
492	              : deterministicSchemeColorHex(seed),
493	        }
494	      : scheme === 'opening_focus'
495	        ? { opacity: 0.045, color: getPlanPalette().regionFillStrong }
496	        : {
497	            opacity: 0.14,
498	
499	            color: getPlanPalette().regionFill,
500	          };
501	
502	  const scale = opts?.roomFillOpacityScale ?? 1;
503	
504	  const mesh = new THREE.Mesh(
505	    geo,
506	
507	    new THREE.MeshBasicMaterial({
508	      color: fill.color,
509	
510	      transparent: true,
511	
512	      opacity: THREE.MathUtils.clamp(fill.opacity * scale, 0, 1),
513	
514	      depthWrite: false,
515	    }),
516	  );
517	
518	  mesh.rotation.x = -Math.PI / 2;
519	
520	  mesh.position.y = PLAN_Y;
521	
522	  mesh.userData.bimPickId = room.id;
523	
524	  const c = centroidMm(room.outlineMm);
525	
526	  mesh.userData.roomLabel = {
527	    cx: ux(c.xMm),
528	    cz: uz(c.yMm),
529	    name: room.name,
530	    areaMm2: polygonAreaMm2(room.outlineMm),
531	  };
532	
533	  return mesh;
534	}
