536	export function planAnnotationLabelSprite(
537	  cxM: number,
538	  czM: number,
539	  text: string,
540	  pickId?: string,
541	  fontScale = 1,
542	): THREE.Sprite {
543	  const scaleMul = Number.isFinite(fontScale) && fontScale > 0 ? fontScale : 1;
544	  const trimmed = text.trim().slice(0, 96);
545	  const safe = trimmed.length ? trimmed : '—';
546	
547	  const doc = typeof globalThis.document !== 'undefined' ? globalThis.document : null;
548	  const emptySprite = (): THREE.Sprite => {
549	    const mat = new THREE.SpriteMaterial({
550	      color: getPlanPalette().tagBg,
551	      transparent: true,
552	      opacity: 0.92,
553	    });
554	    const sprite = new THREE.Sprite(mat);
555	    sprite.position.set(cxM, PLAN_Y + 0.003, czM);
556	    sprite.scale.set(0.08 * scaleMul, 0.03 * scaleMul, 1);
557	    sprite.renderOrder = 10;
558	    sprite.userData.planAnnotationOverlay = true;
559	    if (pickId) sprite.userData.bimPickId = pickId;
560	    return sprite;
561	  };
562	  if (!doc?.createElement) return emptySprite();
563	
564	  const viteMode =
565	    typeof import.meta !== 'undefined' &&
566	    typeof (import.meta as { env?: { MODE?: string } }).env?.MODE === 'string'
567	      ? (import.meta as { env: { MODE: string } }).env.MODE
568	      : '';
569	  if (viteMode === 'test') return emptySprite();
570	
571	  const dpr =
572	    typeof (globalThis as { devicePixelRatio?: number }).devicePixelRatio === 'number'
573	      ? (globalThis as { devicePixelRatio: number }).devicePixelRatio
574	      : 1;
575	  const fontPx = Math.round(64 * Math.min(Math.max(dpr, 1), 2));
576	  const size = Math.max(Math.floor(fontPx * 1.125), 32);
577	  const ch = Math.max(Math.floor(fontPx * 1.5625), 36);
578	
579	  const canvas = doc.createElement('canvas');
580	  canvas.width = size;
581	  canvas.height = ch;
582	  let ctx: CanvasRenderingContext2D | null = null;
583	  try {
584	    ctx = canvas.getContext('2d');
585	  } catch {
586	    ctx = null;
587	  }
588	  if (!ctx) return emptySprite();
589	
590	  ctx.globalAlpha = 0.92;
591	  ctx.strokeStyle = 'rgba(255,255,255,0.78)';
592	  ctx.fillStyle = getPlanPalette().tagText;
593	  ctx.lineWidth = 4;
594	  const pad = Math.max(12, Math.floor(fontPx / 16));
595	  const r = pad * 1.05;
596	  const wBox = canvas.width - pad * 2;
597	  ctx.beginPath();
598	  ctx.moveTo(wBox + pad, canvas.height / 2);
599	  ctx.arcTo(canvas.width - pad + 1e-3, canvas.height / 2, canvas.width - pad, pad, r);
600	  ctx.arcTo(canvas.width - pad, pad + 1e-3, canvas.width / 2, pad, r);
601	  ctx.arcTo(pad + 1e-3, pad, pad, canvas.height / 2, r);
602	  ctx.arcTo(pad, canvas.height / 2, pad, canvas.height - pad, r);
603	  ctx.arcTo(pad + 1e-3, canvas.height - pad, canvas.width / 2, canvas.height - pad, r);
604	  ctx.arcTo(canvas.width - pad, canvas.height - pad, canvas.width - pad, canvas.height / 2, r);
605	  ctx.closePath();
606	  ctx.fill();
607	  ctx.stroke();
608	
609	  ctx.globalAlpha = 1;
610	  ctx.font = `600 ${fontPx}px system-ui,sans-serif`;
611	  // Inverse of tagText for high-contrast room/tag labels on the dark pill.
612	  ctx.fillStyle = readToken('--color-background', '#fafafa');
613	  ctx.strokeStyle = 'rgba(255,255,255,0.35)';
614	  ctx.textAlign = 'center';
615	  ctx.textBaseline = 'middle';
616	  try {
617	    ctx.lineWidth = 3;
618	    ctx.strokeText(safe, canvas.width / 2, canvas.height / 2);
619	  } catch {
620	    /* strokeText unsupported in some canvas implementations */
621	  }
622	  ctx.fillText(safe, canvas.width / 2, canvas.height / 2);
623	
624	  const texture = new THREE.CanvasTexture(canvas);
625	  texture.needsUpdate = true;
626	  const mat = new THREE.SpriteMaterial({
627	    map: texture,
628	    transparent: true,
629	    depthTest: true,
630	    depthWrite: false,
631	  });
632	  const sprite = new THREE.Sprite(mat);
633	  sprite.position.set(cxM, PLAN_Y + 0.003, czM);
634	  sprite.scale.set(0.22 * scaleMul, 0.22 * (canvas.height / canvas.width) * scaleMul, 1);
635	  sprite.renderOrder = 10;
636	  sprite.userData.planAnnotationOverlay = true;
637	  if (pickId) sprite.userData.bimPickId = pickId;
638	  return sprite;
639	}
