665	export function dimensionsThree(d: Extract<Element, { kind: 'dimension' }>): THREE.LineSegments {
666	  const a = new THREE.Vector3(ux(d.aMm.xMm), PLAN_Y + 0.002, uz(d.aMm.yMm));
667	
668	  const b = new THREE.Vector3(ux(d.bMm.xMm), PLAN_Y + 0.002, uz(d.bMm.yMm));
669	
670	  const off = new THREE.Vector3(ux(d.offsetMm.xMm), 0, uz(d.offsetMm.yMm));
671	
672	  const aa = a.clone().add(off);
673	
674	  const bb = b.clone().add(off);
675	
676	  const arr = [
677	    ...a.toArray(),
678	    ...aa.toArray(),
679	    ...aa.toArray(),
680	    ...bb.toArray(),
681	    ...bb.toArray(),
682	    ...b.toArray(),
683	  ];
684	
685	  const geo = new THREE.BufferGeometry();
