690	
691	  const ls = new THREE.LineSegments(
692	    geo,
693	
694	    new THREE.LineBasicMaterial({ color: getPlanPalette().wallSelected }),
695	  );
696	
697	  ls.userData.dimensionSpanMm = dimSpanMm;
698	
699	  return ls;
700	}
