    return { state, effect: { stillActive: true } };
  }
  return {
    state: { phase: 'pick-reference', referenceId: null },
    effect: {
      commitTrim: {
        referenceId: state.referenceId,
        targetId: event.elementId,
        endHint: event.endHint,
      },
      stillActive: true,
    },
  };

