/**
 * Tool registry — spec §16.
 *
 * Single source of truth for the §16 floating tool palette.
 *
 *   - `TOOL_REGISTRY` lists every primary drawing tool with its spec'd
 *     hotkey, lucide icon name (resolved via `Icons[icon]`), and per-mode
 *     visibility.
 *   - `paletteForMode(mode)` returns the ordered tool buttons for a
 *     given workspace mode (Plan, 3D, Plan+3D, Section, etc.).
 *   - `isToolDisabled(tool, document)` lets the palette dim tools that
 *     can't activate (e.g. Floor before any walls exist).
 *
 * Per-tool grammar specs (location-line cycle, chain mode, sketch-vs-
 * pick, etc.) live in `tools/<tool>.ts` and are referenced from this
 * registry by the `kind` discriminator.
 */

import type { TFunction } from 'i18next';

import type { IconName } from '@bim-ai/ui';

export type ToolId =
  | 'select'
  | 'wall'
  | 'door'
  | 'window'
  | 'floor'
  | 'roof'
  | 'stair'
  | 'railing'
  | 'room'
  | 'dimension'
  | 'section'
  | 'tag'
  | 'align'
  | 'split'
  | 'trim'
  | 'wall-join';

/** Modify-group tool IDs — used by ToolPalette to insert a separator. */
export const MODIFY_TOOL_IDS = new Set<ToolId>(['align', 'split', 'trim', 'wall-join']);

export type WorkspaceMode = 'plan' | '3d' | 'plan-3d' | 'section' | 'sheet' | 'schedule' | 'agent';

export interface ToolDefinition {
  id: ToolId;
  label: string;
  icon: IconName;
  /** Hotkey label (the actual key handler is wired by WP-UI-D03). */
  hotkey: string;
  /** Workspace modes where this tool button shows. */
  modes: WorkspaceMode[];
  /** Optional helper text shown in the tooltip. */
  tooltip?: string;
}

export function getToolRegistry(t: TFunction): Record<ToolId, ToolDefinition> {
  return {
    select: {
      id: 'select',
      label: t('tools.select.label'),
      icon: 'select',
      hotkey: 'V',
      modes: ['plan', '3d', 'plan-3d', 'section', 'sheet', 'schedule', 'agent'],
      tooltip: t('tools.select.tooltip'),
    },
    wall: {
      id: 'wall',
      label: t('tools.wall.label'),
      icon: 'wall',
      hotkey: 'W',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.wall.tooltip'),
    },
    door: {
      id: 'door',
      label: t('tools.door.label'),
      icon: 'door',
      hotkey: 'D',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.door.tooltip'),
    },
    window: {
      id: 'window',
      label: t('tools.window.label'),
      icon: 'window',
      hotkey: 'Shift+W',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.window.tooltip'),
    },
    floor: {
      id: 'floor',
      label: t('tools.floor.label'),
      icon: 'floor',
      hotkey: 'F',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.floor.tooltip'),
    },
    roof: {
      id: 'roof',
      label: t('tools.roof.label'),
      icon: 'roof',
      hotkey: 'R',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.roof.tooltip'),
    },
    stair: {
      id: 'stair',
      label: t('tools.stair.label'),
      icon: 'stair',
      hotkey: 'S',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.stair.tooltip'),
    },
    railing: {
      id: 'railing',
      label: t('tools.railing.label'),
      icon: 'railing',
      hotkey: 'Shift+R',
      modes: ['plan', 'plan-3d', '3d'],
      tooltip: t('tools.railing.tooltip'),
    },
    room: {
      id: 'room',
      label: t('tools.room.label'),
      icon: 'room',
      hotkey: 'M',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.room.tooltip'),
    },
    dimension: {
      id: 'dimension',
      label: t('tools.dimension.label'),
      icon: 'dimension',
      hotkey: 'Shift+D',
      modes: ['plan', 'plan-3d', 'section'],
      tooltip: t('tools.dimension.tooltip'),
    },
    section: {
      id: 'section',
      label: t('tools.section.label'),
      icon: 'section',
      hotkey: 'Shift+S',
      modes: ['plan', 'plan-3d', 'section'],
      tooltip: t('tools.section.tooltip'),
    },
    tag: {
      id: 'tag',
      label: t('tools.tag.label'),
      icon: 'tag',
      hotkey: 'T',
      modes: ['plan', 'plan-3d'],
      tooltip: t('tools.tag.tooltip'),
    },
    align: {
      id: 'align',
      label: t('tools.align.label'),
      icon: 'align',
      hotkey: 'AL',
      modes: ['plan'],
      tooltip: t('tools.align.tooltip'),
    },
    split: {
      id: 'split',
      label: t('tools.split.label'),
      icon: 'split',
      hotkey: 'SD',
      modes: ['plan'],
      tooltip: t('tools.split.tooltip'),
    },
    trim: {
      id: 'trim',
      label: t('tools.trim.label'),
      icon: 'trim',
      hotkey: 'TR',
      modes: ['plan'],
      tooltip: t('tools.trim.tooltip'),
    },
    'wall-join': {
      id: 'wall-join',
      label: t('tools.wallJoin.label'),
      icon: 'wall-join',
      hotkey: 'WJ',
      modes: ['plan'],
      tooltip: t('tools.wallJoin.tooltip'),
    },
  };
}

const PALETTE_ORDER: ToolId[] = [
  'select',
  'wall',
  'door',
  'window',
  'floor',
  'roof',
  'stair',
  'railing',
  'room',
  'dimension',
  'section',
  'tag',
  'align',
  'split',
  'trim',
  'wall-join',
];

export function paletteForMode(mode: WorkspaceMode, t: TFunction): ToolDefinition[] {
  const registry = getToolRegistry(t);
  return PALETTE_ORDER.map((id) => registry[id]).filter((tool) => tool.modes.includes(mode));
}

export interface ToolDisabledContext {
  hasAnyWall: boolean;
  hasAnyFloor: boolean;
  hasAnySelection: boolean;
}

export function isToolDisabled(
  toolId: ToolId,
  ctx: ToolDisabledContext,
  t: TFunction,
): { disabled: boolean; reason?: string } {
  switch (toolId) {
    case 'floor':
      if (!ctx.hasAnyWall) return { disabled: true, reason: t('tools.disabled.drawWallFirst') };
      return { disabled: false };
    case 'roof':
      if (!ctx.hasAnyWall) return { disabled: true, reason: t('tools.disabled.drawWallFirst') };
      return { disabled: false };
    case 'railing':
      if (!ctx.hasAnyFloor && !ctx.hasAnyWall) {
        return { disabled: true, reason: t('tools.disabled.addStairFirst') };
      }
      return { disabled: false };
    case 'dimension':
      if (!ctx.hasAnyWall)
        return { disabled: true, reason: t('tools.disabled.nothingToDimension') };
      return { disabled: false };
    default:
      return { disabled: false };
  }
}

import type {
  Element,
  ModelDelta,
  PerspectiveId,
  Snapshot,
  Violation,
  WorkspaceLayoutPreset,
} from '@bim-ai/core';

import type { WallLocationLine } from '../tools/toolGrammar';
import type { PlanPresentationPreset } from '../plan/symbology';
import type {
  PlanProjectionPrimitivesV1Wire,
  PlanCategoryGraphicHintsV0Wire,
  PlanRoomColorLegendRow,
  RoomProgrammeLegendEvidenceV0,
} from '../plan/planProjectionWire';
import type { LevelElevationPropagationEvidenceV0 } from '../workspace/levelDatumPropagationReadout';

export type PlanRoomSchemeWireReadout = {
  roomColorLegendRows: PlanRoomColorLegendRow[];
  programmeLegendEvidence: RoomProgrammeLegendEvidenceV0 | null;
  planCategoryGraphicHintsV0?: PlanCategoryGraphicHintsV0Wire | null;
};

export type ViewerMode = 'plan_canvas' | 'orbit_3d';

export type PlanTool =
  | 'select'
  | 'wall'
  | 'floor'
  | 'door'
  | 'window'
  | 'room'
  | 'room_rectangle'
  | 'grid'
  | 'dimension'
  | 'align'
  | 'split'
  | 'trim'
  | 'wall-join';

export type PresencePeers = Record<
  string,
  {
    peerId?: string;
    userId?: string;
    name?: string;
    color?: string;
    cursorMm?: { xMm: number; yMm: number };
    selectionId?: string;
    viewer?: string;
  }
>;

export type UxComment = {
  id: string;
  userDisplay: string;
  body: string;
  elementId?: string | null;
  levelId?: string | null;
  anchorXMm?: number | null;
  anchorYMm?: number | null;
  resolved: boolean;
  createdAt?: string;
};

export type ActivityEvent = {
  id: number;
  userId: string;
  revisionAfter: number;
  createdAt: string;
  commandTypes: string[];
};

export type CategoryOverride = {
  projection?: {
    lineWeightFactor?: number;
    lineColor?: string | null;
    linePattern?: string | null;
    fillColor?: string | null;
    halftone?: boolean;
  };
  cut?: {
    lineWeightFactor?: number;
    lineColor?: string | null;
    linePattern?: string | null;
    fillColor?: string | null;
    halftone?: boolean;
  };
  visible?: boolean;
};

export type CategoryOverrides = Record<string, CategoryOverride>;

export type StoreState = {
  modelId?: string;
  revision: number;
  elementsById: Record<string, Element>;
  violations: Violation[];
  selectedId?: string;
  viewerMode: ViewerMode;
  planTool: PlanTool;
  activeLevelId?: string;
  planPresentationPreset: PlanPresentationPreset;
  activePlanViewId?: string;
  /** Saved 3D viewpoint whose clip/layer tweaks should persist via `updateElementProperty`. */
  activeViewpointId?: string;
  /** When set, plan canvas prefers server `planProjectionWire_v1.primitives` (WP-C02/C03). */
  planProjectionPrimitives: PlanProjectionPrimitivesV1Wire | null;
  /** Last plan wire legend + programme digest readout for workbench panels (Prompt-3 room scheme). */
  planRoomSchemeWireReadout: PlanRoomSchemeWireReadout | null;
  /** Active Schedules tab row count for browser rendering budget readout (Prompt-8). */
  scheduleBudgetHydration: { tab: string; rowCount: number } | null;
  /** Latest server `levelElevationPropagationEvidence_v0` after apply (Prompt-1). */
  lastLevelElevationPropagationEvidence: LevelElevationPropagationEvidenceV0 | null;
  viewerClipElevMm: number | null;
  /** Optional lower bound — clips geometry *below* this world Y (mm) for a reproducible slab cut. */
  viewerClipFloorElevMm: number | null;
  /** When true for a semantic kind (`wall`, `roof`, …), that category is hidden in 3D. */
  viewerCategoryHidden: Record<string, boolean>;
  wallLocationLine: WallLocationLine;
  floorBoundaryOffsetMm: number;
  orthoSnapHold: boolean;
  userId: string;
  userDisplayName: string;
  peerId: string;
  presencePeers: PresencePeers;
  comments: UxComment[];
  activityEvents: ActivityEvent[];
  buildingPreset: string;
  planHudMm?: { xMm: number; yMm: number };
  workspaceLayoutPreset: WorkspaceLayoutPreset;
  perspectiveId: PerspectiveId;

  /** Bump to push a saved orbit viewpoint camera into Viewport three.js rig (WP-E02/E03). */
  orbitCameraNonce: number;
  /** Optional camera pose in model mm conventions (plan x/zMm as world-up). */
  orbitCameraPoseMm: {
    position: { xMm: number; yMm: number; zMm: number };
    target: { xMm: number; yMm: number; zMm: number };
    up: { xMm: number; yMm: number; zMm: number };
  } | null;

  hydrateFromSnapshot: (snap: Snapshot) => void;
  applyDelta: (d: ModelDelta) => void;
  select: (id?: string) => void;
  setViewerMode: (m: ViewerMode) => void;
  setPlanTool: (t: PlanTool) => void;
  setActiveLevelId: (id: string | undefined) => void;
  setWallLocationLine: (loc: WallLocationLine) => void;
